import{_ as a,o as s,c as r,ag as i}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Basic & Reversed Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Basic-&-Reversed-Cards.md","filePath":"Basic-&-Reversed-Cards.md","lastUpdated":1772690052000}'),o={name:"Basic-&-Reversed-Cards.md"};function t(d,e,l,n,c,p){return s(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="basic-reversed-cards" tabindex="-1">Basic &amp; Reversed Cards <a class="header-anchor" href="#basic-reversed-cards" aria-label="Permalink to &quot;Basic &amp; Reversed Cards&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Basic cards show a question first, then an answer. Reversed cards add a second card automatically so you study both directions.</p><h2 id="basic-format" tabindex="-1">Basic Format <a class="header-anchor" href="#basic-format" aria-label="Permalink to &quot;Basic Format&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | Title |</span></span>
<span class="line"><span>Q | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span>
<span class="line"><span>I | Extra context |</span></span>
<span class="line"><span>G | Geography |</span></span></code></pre></div><ul><li>Required fields: <code>Q</code> and <code>A</code></li><li>Optional fields: <code>T</code>, <code>I</code>, <code>G</code></li></ul><h2 id="modal-steps" tabindex="-1">Modal Steps <a class="header-anchor" href="#modal-steps" aria-label="Permalink to &quot;Modal Steps&quot;">​</a></h2><ol><li>Right-click in a note.</li><li>Choose <strong>Add flashcard → Basic Card</strong>.</li><li>Fill in fields and save.</li></ol><h2 id="reverse-mode" tabindex="-1">Reverse Mode <a class="header-anchor" href="#reverse-mode" aria-label="Permalink to &quot;Reverse Mode&quot;">​</a></h2><p>With reverse enabled, LearnKit creates:</p><ol><li>Question → Answer</li><li>Answer → Question</li></ol><p>Use the reverse option in the modal to enable this.</p><h2 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h2><p>After revealing the answer, grade your recall:</p><ul><li>two-button mode: Again / Good</li><li>four-button mode: Again / Hard / Good / Easy</li></ul><p>See <a href="./Grading">Grading</a>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>If <code>Q</code> or <code>A</code> is missing, the card cannot work correctly.</li><li>Keep one fact per card for better retention.</li><li>Use <code>I</code> for hints or references instead of making <code>A</code> too long.</li><li>Use groups to organize by topic.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Creating-Cards">Creating Cards</a></li><li><a href="./Cards">Cards</a></li></ul>`,21)])])}const f=a(o,[["render",t]]);export{u as __pageData,f as default};
